import {
  Button,
  Modal,
  ModalVariant,
  ModalHeader,
  ModalBody,
  ModalFooter,
  Content,
  ContentVariants,
  Alert,
  Stack,
  StackItem,
} from "@patternfly/react-core";
import { unpauseNodeHealthCheck } from "apis/nodeHealthCheckApis";
import * as React from "react";

import { NodeHealthCheckModalProps } from "./propTypes";
import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
import { InfoCircleIcon } from "@patternfly/react-icons";
import { t_color_blue_40 as infoColor } from "@patternfly/react-tokens";
import EnhancedTextList from "components/shared/EnhancedTextList";

export const UnpauseModal: React.FC<NodeHealthCheckModalProps> = ({
  nodeHealthCheck,
  isOpen,
  onClose,
}) => {
  const { t } = useNodeHealthCheckTranslation();
  const [isSubmitting, setIsSubmitting] = React.useState<boolean>();
  const [error, setError] = React.useState<boolean>();
  const pauseRequests = nodeHealthCheck.spec?.pauseRequests || [];
  const onSubmit = async () => {
    setIsSubmitting(true);
    try {
      await unpauseNodeHealthCheck(nodeHealthCheck);
    } catch (err) {
      setError(err);
    }
    setIsSubmitting(false);
    onClose();
  };
  const infoMessage = t("All the pause reasons will be removed");
  return (
    <Modal
      className="nhc-modal"
      isOpen={isOpen}
      onClose={onClose}
      variant={ModalVariant.small}
    >
      <ModalHeader
        title={t("Unpause NodeHealthCheck")}
        description={t("Are you sure you want to unpause Node health check?")}
      />
      <ModalBody>
        <Stack hasGutter>
          <StackItem>
            <Content component={ContentVariants.h4}>{t(`Pause reasons`)}</Content>
          </StackItem>
          <StackItem>
            <EnhancedTextList textList={pauseRequests} />
          </StackItem>
          <StackItem>
            <Content>
              <InfoCircleIcon
                style={{ color: infoColor.value, fontSize: "0.875rem", verticalAlign: "middle" }}
              />
              &nbsp;{`${infoMessage}`}
            </Content>
          </StackItem>
        </Stack>
        {error && (
          <Alert variant="danger" title={t("Failed to unpause")} isInline />
        )}
      </ModalBody>
      <ModalFooter>
        <Button
          key="confirm"
          variant="primary"
          onClick={() => void onSubmit()}
          isLoading={isSubmitting}
          isDisabled={isSubmitting}
          data-test="confirm"
        >
          {t("Unpause")}
        </Button>
        <Button
          key="cancel"
          variant="secondary"
          onClick={onClose}
          data-test="cancel"
          isDisabled={isSubmitting}
        >
          {t("Cancel")}
        </Button>
      </ModalFooter>
    </Modal>
  );
};
